SELECT ROUND(AVG(es.score), 2) as average_score
FROM exam_scores es
INNER JOIN exams e ON es.exam_id = e.exam_id
WHERE e.course_id = #{courseId}
AND es.student_id = #{studentId}
AND es.score IS NOT NULL
